from sympy.functions.combinatorial.numbers import stirling
cycle=lambda n,k: stirling(n,k,kind=1)
A059418=lambda n, k: cycle(n-1,k-1) + sum(cycle(n-1, i)*2**(i-k) for i in range(k, n))
